args.script:
// Check what prefabs are actually referenced in the scene via FindObjectsOfType
// Also check TowerSelectPanel for button prefab references
var allMono = UnityEngine.Object.FindObjectsOfType<UnityEngine.MonoBehaviour>();
foreach (var m in allMono)
{
    var typeName = m.GetType().Name;
    if (typeName.Contains("Tower") || typeName.Contains("tower") || typeName.Contains("Archer") || typeName.Contains("Projectile"))
    {
        var go = m.gameObject;
        UnityEngine.Debug.Log($"Found: {typeName} on '{go.name}' (path: {GetPath(go)})");
    }
}

string GetPath(UnityEngine.GameObject go)
{
    var path = go.name;
    while (go.transform.parent != null)
    {
        go = go.transform.parent.gameObject;
        path = go.name + "/" + path;
    }
    return path;
}

// Check if the "1" variant prefabs are referenced by anything in the scene or other assets
var paths = new string[] {
    "Assets/Prefabs/Towers/Tower_Archer 1.prefab",
    "Assets/Prefabs/Towers/Projectile_Arrow 1.prefab",
    "Assets/Prefabs/Towers/Projectile_Arrow.prefab",
    "Assets/Prefabs/Towers/Tower_Archer.prefab",
    "Assets/Prefabs/Projectiles/Projectile_Arrow.prefab"
};

foreach (var p in paths)
{
    var guid = UnityEditor.AssetDatabase.AssetPathToGUID(p);
    var obj = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.Object>(p);
    var objName = obj != null ? obj.name : "NOT FOUND";

    // Find what references this asset
    var refs = UnityEditor.AssetDatabase.GetDependencies(p, false);
    var refList = string.Join(", ", refs);
    UnityEngine.Debug.Log($"[{objName}] path={p} guid={guid} deps=[{refList}]");
}

// Also check which Projectile_Arrow in Towers/ differs from the one in Projectiles/
var arrow1 = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.GameObject>("Assets/Prefabs/Towers/Projectile_Arrow.prefab");
var arrow2 = UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.GameObject>("Assets/Prefabs/Projectiles/Projectile_Arrow.prefab");
if (arrow1 != null && arrow2 != null)
{
    var g1 = UnityEditor.AssetDatabase.AssetPathToGUID("Assets/Prefabs/Towers/Projectile_Arrow.prefab");
    var g2 = UnityEditor.AssetDatabase.AssetPathToGUID("Assets/Prefabs/Projectiles/Projectile_Arrow.prefab");
    UnityEngine.Debug.Log($"Towers/Projectile_Arrow GUID: {g1}");
    UnityEngine.Debug.Log($"Projectiles/Projectile_Arrow GUID: {g2}");
    UnityEngine.Debug.Log($"Same GUID (same asset): {g1 == g2}");
}

