args.script:
// List empty folders that can be cleaned up
var emptyFolders = new System.Collections.Generic.List<string>();
var allFolders = new string[] {
    "Assets/Animations",
    "Assets/Art/Backgrounds",
    "Assets/Art/Characters",
    "Assets/Art/Effects",
    "Assets/Art/Enemies",
    "Assets/Art/Towers",
    "Assets/Audio/BGM",
    "Assets/Audio/SFX",
    "Assets/Materials",
    "Assets/Prefabs/Effects",
    "Assets/Prefabs/Heroes",
    "Assets/Scripts/AI"
};

foreach (var folder in allFolders)
{
    if (!System.IO.Directory.Exists(folder)) continue;
    var files = System.IO.Directory.GetFiles(folder, "*.*", System.IO.SearchOption.TopDirectoryOnly)
        .Where(f => !f.EndsWith(".meta")).ToArray();
    var subdirs = System.IO.Directory.GetDirectories(folder, "*", System.IO.SearchOption.TopDirectoryOnly)
        .Where(d => !System.IO.File.Exists(d + ".meta") || true).ToArray();

    var fileCount = files.Length;
    var subCount = subdirs.Length;

    if (fileCount == 0 && subCount == 0)
    {
        UnityEngine.Debug.Log($"EMPTY: {folder}");
        emptyFolders.Add(folder);
    }
    else
    {
        var fileList = string.Join(", ", files.Select(f => System.IO.Path.GetFileName(f)).Take(5));
        UnityEngine.Debug.Log($"HAS CONTENT ({fileCount} files, {subCount} dirs): {folder} → [{fileList}]");
    }
}

UnityEngine.Debug.Log($"\nTotal empty folders: {emptyFolders.Count}");
foreach (var f in emptyFolders) UnityEngine.Debug.Log($"  → {f}");

