// Verify LevelBuilder still has its tile references after moving assets
var lb = UnityEngine.Object.FindObjectOfType<TowerDefense.Map.LevelBuilder>();
if (lb != null)
{
    var lbType = lb.GetType();
    var fields = lbType.GetFields(System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.Public);
    int nullCount = 0;
    int totalRefs = 0;
    foreach (var f in fields)
    {
        if (typeof(UnityEngine.Object).IsAssignableFrom(f.FieldType) || f.FieldType.IsArray)
        {
            var val = f.GetValue(lb);
            if (val is UnityEngine.Object[] arr)
            {
                totalRefs += arr.Length;
                foreach (var item in arr)
                {
                    if (item == null) nullCount++;
                    else UnityEngine.Debug.Log($"  {f.Name}[{System.Array.IndexOf(arr, item)}] = {item.name} ({item.GetType().Name})");
                }
            }
            else if (val is UnityEngine.Object obj)
            {
                totalRefs++;
                if (obj == null) nullCount++;
                else UnityEngine.Debug.Log($"  {f.Name} = {obj.name} ({obj.GetType().Name})");
            }
        }
    }
    UnityEngine.Debug.Log($"LevelBuilder refs: {totalRefs} total, {nullCount} null");
}
else
{
    UnityEngine.Debug.Log("LevelBuilder not found in scene");
}

