var ps = UnityEngine.Object.FindObjectOfType<UnityEngine.ParticleSystem>();
if (ps != null)
{
    var renderer = ps.GetComponent<UnityEngine.ParticleSystemRenderer>();

    // Create a default particle material
    var mat = new UnityEngine.Material(UnityEngine.Shader.Find("Particles/Standard Unlit"));
    mat.color = UnityEngine.Color.white;
    mat.SetFloat("_Mode", 1); // Additive
    mat.renderQueue = 3100;

    renderer.sharedMaterial = mat;

    // Change render mode to Billboard for Canvas compatibility
    renderer.renderMode = UnityEngine.ParticleSystemRenderMode.Billboard;

    // Make sure it's in front of other canvas elements
    renderer.sortingOrder = 100;

    UnityEngine.Debug.Log($"Material assigned: {renderer.sharedMaterial.name}");
    UnityEngine.Debug.Log($"RenderMode: {renderer.renderMode}");
    UnityEngine.Debug.Log($"SortingOrder: {renderer.sortingOrder}");

    // Restart the particle system
    ps.Stop(true, UnityEngine.ParticleSystemStopBehavior.StopEmittingAndClear);
    ps.Play();
    UnityEngine.Debug.Log($"PS isPlaying: {ps.isPlaying}");
}

