args.script:
var ps = UnityEngine.Object.FindObjectOfType<UnityEngine.ParticleSystem>();
if (ps != null)
{
    var main = ps.main;
    // Make snow fall slower and live longer for a gentle snow effect
    main.startSpeed = 1.5f;           // slower fall
    main.startLifetime = 8f;           // live longer
    main.startSize = 0.3f;            // smaller flakes
    main.maxParticles = 500;          // more particles
    main.simulationSpace = UnityEngine.ParticleSystemSimulationSpace.World; // world space so snow falls naturally

    var emission = ps.emission;
    emission.rateOverTime = 50;        // more snow per second

    var shape = ps.shape;
    // Shape is Rectangle, make it wider to cover the screen
    shape.scale = new UnityEngine.Vector3(1500f, 1f, 1f);

    // Add gravity-like downward drift
    var velocityOverLifetime = ps.velocityOverLifetime;
    velocityOverLifetime.enabled = true;
    velocityOverLifetime.y = new UnityEngine.ParticleSystem.MinMaxCurve(-0.5f);

    // Add some horizontal drift for natural snow
    var forceOverLifetime = ps.forceOverLifetime;
    forceOverLifetime.enabled = true;
    forceOverLifetime.x = new UnityEngine.ParticleSystem.MinMaxCurve(-0.3f, 0.3f);

    // Add gentle wobble
    var noise = ps.noise;
    noise.enabled = true;
    noise.strength = 0.2f;
    noise.frequency = 0.5f;

    // Color: white with some alpha variation
    var colorOverLifetime = ps.colorOverLifetime;
    colorOverLifetime.enabled = true;
    var grad = new UnityEngine.Gradient();
    grad.SetKeys(
        new UnityEngine.GradientColorKey[] { new UnityEngine.GradientColorKey(UnityEngine.Color.white, 0f), new UnityEngine.GradientColorKey(UnityEngine.Color.white, 1f) },
        new UnityEngine.GradientAlphaKey[] { new UnityEngine.GradientAlphaKey(0f, 0f), new UnityEngine.GradientAlphaKey(0.8f, 0.2f), new UnityEngine.GradientAlphaKey(0.6f, 0.8f), new UnityEngine.GradientAlphaKey(0f, 1f) }
    );
    colorOverLifetime.color = grad;

    // Restart
    ps.Stop(true, UnityEngine.ParticleSystemStopBehavior.StopEmittingAndClear);
    ps.Play();

    UnityEngine.Debug.Log($"Snow settings updated!");
    UnityEngine.Debug.Log($"  speed: {main.startSpeed.constant}, lifetime: {main.startLifetime.constant}");
    UnityEngine.Debug.Log($"  size: {main.startSize.constant}, maxParticles: {main.maxParticles}");
    UnityEngine.Debug.Log($"  emissionRate: {emission.rateOverTime.constant}");
    UnityEngine.Debug.Log($"  shapeScale: {shape.scale}");
    UnityEngine.Debug.Log($"  particleCount: {ps.particleCount}");
}

