var ps = UnityEngine.Object.FindObjectOfType<UnityEngine.ParticleSystem>();
if (ps == null) { UnityEngine.Debug.Log("No ParticleSystem found!"); return; }

var go = ps.gameObject;
var parent = go.transform.parent;
UnityEngine.Debug.Log($"Current parent: {(parent != null ? parent.name : "null")}");

// Check canvas
var canvases = UnityEngine.Object.FindObjectsOfType<UnityEngine.Canvas>();
foreach (var c in canvases)
{
    UnityEngine.Debug.Log($"Canvas: {c.name}, renderMode={c.renderMode}, scaleFactor={c.scaleFactor}");
}

// The problem: PS is child of "背景" which is child of Canvas
// Canvas is ScreenSpaceCamera with scale 0.11
// This squashes the particle system
// Solution: Move PS out of Canvas to be sibling of Canvas in world space

// Reparent to root (same level as Canvas)
go.transform.SetParent(null);

// Set position to cover the camera view
var cam = UnityEngine.Camera.main;
if (cam != null)
{
    // Place in front of camera
    var camPos = cam.transform.position;
    var camForward = cam.transform.forward;
    go.transform.position = camPos + camForward * 50f;

    // Rotate to face down (snow falls downward)
    go.transform.rotation = UnityEngine.Quaternion.Euler(90f, 0f, 0f);

    UnityEngine.Debug.Log($"New position: {go.transform.position}");
    UnityEngine.Debug.Log($"New rotation: {go.transform.rotation.eulerAngles}");
}

// Reset scale
go.transform.localScale = UnityEngine.Vector3.one;

UnityEngine.Debug.Log($"New parent: {(go.transform.parent != null ? go.transform.parent.name : "ROOT")}");

