// Build the ShopPanel UI hierarchy under Canvas
var canvas = UnityEngine.Object.FindObjectOfType<UnityEngine.Canvas>();
if (canvas == null) { UnityEngine.Debug.Log("No Canvas found!"); return; }

var canvasTransform = canvas.transform;

// 1. ShopPanel root (full-screen overlay)
var shopPanelObj = new UnityEngine.GameObject("ShopPanel");
shopPanelObj.transform.SetParent(canvasTransform, false);
var shopPanelRect = shopPanelObj.AddComponent<UnityEngine.RectTransform>();
shopPanelRect.anchorMin = UnityEngine.Vector2.zero;
shopPanelRect.anchorMax = UnityEngine.Vector2.one;
shopPanelRect.offsetMin = UnityEngine.Vector2.zero;
shopPanelRect.offsetMax = UnityEngine.Vector2.zero;

// Background overlay (semi-transparent dark)
var bgImage = shopPanelObj.AddComponent<UnityEngine.UI.Image>();
bgImage.color = new UnityEngine.Color(0f, 0f, 0f, 0.7f);
bgImage.raycastTarget = true;

// Add ShopPanel component
var shopPanelComp = shopPanelObj.AddComponent<TowerDefense.UI.ShopPanel>();

// 2. Panel frame (centered card)
var frameObj = new UnityEngine.GameObject("Frame");
frameObj.transform.SetParent(shopPanelObj.transform, false);
var frameRect = frameObj.AddComponent<UnityEngine.RectTransform>();
frameRect.anchorMin = new UnityEngine.Vector2(0.1f, 0.08f);
frameRect.anchorMax = new UnityEngine.Vector2(0.9f, 0.92f);
frameRect.offsetMin = UnityEngine.Vector2.zero;
frameRect.offsetMax = UnityEngine.Vector2.zero;
var frameImage = frameObj.AddComponent<UnityEngine.UI.Image>();
frameImage.color = new UnityEngine.Color(0.12f, 0.12f, 0.18f, 0.95f);

// 3. Title bar
var titleBar = new UnityEngine.GameObject("TitleBar");
titleBar.transform.SetParent(frameObj.transform, false);
var titleBarRect = titleBar.AddComponent<UnityEngine.RectTransform>();
titleBarRect.anchorMin = new UnityEngine.Vector2(0f, 0.88f);
titleBarRect.anchorMax = UnityEngine.Vector2.one;
titleBarRect.offsetMin = UnityEngine.Vector2.zero;
titleBarRect.offsetMax = UnityEngine.Vector2.zero;
var titleBarImage = titleBar.AddComponent<UnityEngine.UI.Image>();
titleBarImage.color = new UnityEngine.Color(0.15f, 0.15f, 0.25f, 1f);

// Title text
var titleTextObj = new UnityEngine.GameObject("TitleText");
titleTextObj.transform.SetParent(titleBar.transform, false);
var titleTextRect = titleTextObj.AddComponent<UnityEngine.RectTransform>();
titleTextRect.anchorMin = new UnityEngine.Vector2(0.05f, 0f);
titleTextRect.anchorMax = new UnityEngine.Vector2(0.8f, 1f);
titleTextRect.offsetMin = UnityEngine.Vector2.zero;
titleTextRect.offsetMax = UnityEngine.Vector2.zero;
var titleText = titleTextObj.AddComponent<UnityEngine.UI.Text>();
titleText.text = "🏪 商  城";
titleText.fontSize = 42;
titleText.fontStyle = UnityEngine.FontStyle.Bold;
titleText.color = UnityEngine.Color.white;
titleText.alignment = UnityEngine.TextAnchor.MiddleLeft;

// Close button
var closeBtnObj = new UnityEngine.GameObject("CloseButton");
closeBtnObj.transform.SetParent(titleBar.transform, false);
var closeBtnRect = closeBtnObj.AddComponent<UnityEngine.RectTransform>();
closeBtnRect.anchorMin = new UnityEngine.Vector2(0.88f, 0.1f);
closeBtnRect.anchorMax = new UnityEngine.Vector2(0.98f, 0.9f);
closeBtnRect.offsetMin = UnityEngine.Vector2.zero;
closeBtnRect.offsetMax = UnityEngine.Vector2.zero;
var closeBtnImage = closeBtnObj.AddComponent<UnityEngine.UI.Image>();
closeBtnImage.color = new UnityEngine.Color(0.8f, 0.2f, 0.2f, 1f);
var closeBtn = closeBtnObj.AddComponent<UnityEngine.UI.Button>();
var closeBtnText = new UnityEngine.GameObject("Text");
closeBtnText.transform.SetParent(closeBtnObj.transform, false);
var closeBtnTextRect = closeBtnText.AddComponent<UnityEngine.RectTransform>();
closeBtnTextRect.anchorMin = UnityEngine.Vector2.zero;
closeBtnTextRect.anchorMax = UnityEngine.Vector2.one;
closeBtnTextRect.offsetMin = UnityEngine.Vector2.zero;
closeBtnTextRect.offsetMax = UnityEngine.Vector2.zero;
var closeText = closeBtnText.AddComponent<UnityEngine.UI.Text>();
closeText.text = "✕";
closeText.fontSize = 36;
closeText.color = UnityEngine.Color.white;
closeText.alignment = UnityEngine.TextAnchor.MiddleCenter;

// 4. Tab bar (below title)
var tabBarObj = new UnityEngine.GameObject("TabBar");
tabBarObj.transform.SetParent(frameObj.transform, false);
var tabBarRect = tabBarObj.AddComponent<UnityEngine.RectTransform>();
tabBarRect.anchorMin = new UnityEngine.Vector2(0f, 0.78f);
tabBarRect.anchorMax = new UnityEngine.Vector2(1f, 0.88f);
tabBarRect.offsetMin = UnityEngine.Vector2.zero;
tabBarRect.offsetMax = UnityEngine.Vector2.zero;

// Tab buttons
string[] tabNames = {"资源", "英雄", "防御塔", "特惠"};
var tabBtns = new UnityEngine.UI.Button[4];
for (int i = 0; i < 4; i++)
{
    var tabObj = new UnityEngine.GameObject($"Tab_{tabNames[i]}");
    tabObj.transform.SetParent(tabBarObj.transform, false);
    var tabRect = tabObj.AddComponent<UnityEngine.RectTransform>();
    float w = 0.24f;
    float gap = 0.01f;
    float startX = 0.01f + i * (w + gap);
    tabRect.anchorMin = new UnityEngine.Vector2(startX, 0.05f);
    tabRect.anchorMax = new UnityEngine.Vector2(startX + w, 0.95f);
    tabRect.offsetMin = UnityEngine.Vector2.zero;
    tabRect.offsetMax = UnityEngine.Vector2.zero;
    var tabImg = tabObj.AddComponent<UnityEngine.UI.Image>();
    tabImg.color = new UnityEngine.Color(0.25f, 0.25f, 0.35f, 1f);
    tabBtns[i] = tabObj.AddComponent<UnityEngine.UI.Button>();

    var tabTextObj = new UnityEngine.GameObject("Text");
    tabTextObj.transform.SetParent(tabObj.transform, false);
    var tabTextRect = tabTextObj.AddComponent<UnityEngine.RectTransform>();
    tabTextRect.anchorMin = UnityEngine.Vector2.zero;
    tabTextRect.anchorMax = UnityEngine.Vector2.one;
    tabTextRect.offsetMin = UnityEngine.Vector2.zero;
    tabTextRect.offsetMax = UnityEngine.Vector2.zero;
    var tabText = tabTextObj.AddComponent<UnityEngine.UI.Text>();
    tabText.text = tabNames[i];
    tabText.fontSize = 30;
    tabText.color = UnityEngine.Color.white;
    tabText.alignment = UnityEngine.TextAnchor.MiddleCenter;
}

// 5. Scroll View for items
var scrollObj = new UnityEngine.GameObject("ScrollView");
scrollObj.transform.SetParent(frameObj.transform, false);
var scrollRect = scrollObj.AddComponent<UnityEngine.RectTransform>();
scrollRect.anchorMin = new UnityEngine.Vector2(0.02f, 0.02f);
scrollRect.anchorMax = new UnityEngine.Vector2(0.98f, 0.76f);
scrollRect.offsetMin = UnityEngine.Vector2.zero;
scrollRect.offsetMax = UnityEngine.Vector2.zero;
var scrollImg = scrollObj.AddComponent<UnityEngine.UI.Image>();
scrollImg.color = new UnityEngine.Color(0.08f, 0.08f, 0.12f, 0.5f);
var scroll = scrollObj.AddComponent<UnityEngine.UI.ScrollRect>();

// Viewport
var viewportObj = new UnityEngine.GameObject("Viewport");
viewportObj.transform.SetParent(scrollObj.transform, false);
var viewportRect = viewportObj.AddComponent<UnityEngine.RectTransform>();
viewportRect.anchorMin = UnityEngine.Vector2.zero;
viewportRect.anchorMax = UnityEngine.Vector2.one;
viewportRect.offsetMin = UnityEngine.Vector2.zero;
viewportRect.offsetMax = UnityEngine.Vector2.zero;
viewportRect.pivot = new UnityEngine.Vector2(0.5f, 1f);
var viewportMask = viewportObj.AddComponent<UnityEngine.UI.Image>();
viewportMask.color = new UnityEngine.Color(1f, 1f, 1f, 0.01f);
var mask = viewportObj.AddComponent<UnityEngine.UI.Mask>();
mask.showMaskGraphic = false;

// Content with GridLayoutGroup
var contentObj = new UnityEngine.GameObject("Content");
contentObj.transform.SetParent(viewportObj.transform, false);
var contentRect = contentObj.AddComponent<UnityEngine.RectTransform>();
contentRect.anchorMin = new UnityEngine.Vector2(0f, 1f);
contentRect.anchorMax = new UnityEngine.Vector2(1f, 1f);
contentRect.offsetMin = UnityEngine.Vector2.zero;
contentRect.offsetMax = UnityEngine.Vector2.zero;
var grid = contentObj.AddComponent<UnityEngine.UI.GridLayoutGroup>();
grid.cellSize = new UnityEngine.Vector2(280, 360);
grid.spacing = new UnityEngine.Vector2(20, 20);
grid.padding = new UnityEngine.RectOffset(20, 20, 20, 20);
grid.startAxis = UnityEngine.UI.GridLayoutGroup.Axis.Horizontal;
grid.childAlignment = UnityEngine.TextAnchor.UpperCenter;
grid.constraint = UnityEngine.UI.GridLayoutGroup.Constraint.FixedColumnCount;
grid.constraintCount = 3;
var contentSizeFitter = contentObj.AddComponent<UnityEngine.UI.ContentSizeFitter>();
contentSizeFitter.horizontalFit = UnityEngine.UI.ContentSizeFitter.FitMode.PreferredSize;
contentSizeFitter.verticalFit = UnityEngine.UI.ContentSizeFitter.FitMode.PreferredSize;

scroll.viewport = viewportRect;
scroll.content = contentRect;
scroll.horizontal = false;
scroll.vertical = true;

// 6. ShopItemPrefab (template for each item card)
var itemPrefabObj = new UnityEngine.GameObject("ShopItemPrefab");
itemPrefabObj.transform.SetParent(contentObj.transform, false);
var itemRect = itemPrefabObj.AddComponent<UnityEngine.RectTransform>();
itemRect.sizeDelta = new UnityEngine.Vector2(280, 360);

// Card background
var cardBg = itemPrefabObj.AddComponent<UnityEngine.UI.Image>();
cardBg.color = new UnityEngine.Color(0.2f, 0.2f, 0.3f, 1f);

// Icon area
var iconObj = new UnityEngine.GameObject("Icon");
iconObj.transform.SetParent(itemPrefabObj.transform, false);
var iconRect = iconObj.AddComponent<UnityEngine.RectTransform>();
iconRect.anchorMin = new UnityEngine.Vector2(0.1f, 0.4f);
iconRect.anchorMax = new UnityEngine.Vector2(0.9f, 0.85f);
iconRect.offsetMin = UnityEngine.Vector2.zero;
iconRect.offsetMax = UnityEngine.Vector2.zero;
var iconImage = iconObj.AddComponent<UnityEngine.UI.Image>();
iconImage.color = new UnityEngine.Color(0.3f, 0.3f, 0.45f, 1f);

// Name text
var nameObj = new UnityEngine.GameObject("NameText");
nameObj.transform.SetParent(itemPrefabObj.transform, false);
var nameRect = nameObj.AddComponent<UnityEngine.RectTransform>();
nameRect.anchorMin = new UnityEngine.Vector2(0.05f, 0.25f);
nameRect.anchorMax = new UnityEngine.Vector2(0.95f, 0.38f);
nameRect.offsetMin = UnityEngine.Vector2.zero;
nameRect.offsetMax = UnityEngine.Vector2.zero;
var nameText = nameObj.AddComponent<UnityEngine.UI.Text>();
nameText.fontSize = 22;
nameText.fontStyle = UnityEngine.FontStyle.Bold;
nameText.color = UnityEngine.Color.white;
nameText.alignment = UnityEngine.TextAnchor.MiddleCenter;

// Desc text
var descObj = new UnityEngine.GameObject("DescText");
descObj.transform.SetParent(itemPrefabObj.transform, false);
var descRect = descObj.AddComponent<UnityEngine.RectTransform>();
descRect.anchorMin = new UnityEngine.Vector2(0.05f, 0.15f);
descRect.anchorMax = new UnityEngine.Vector2(0.95f, 0.24f);
descRect.offsetMin = UnityEngine.Vector2.zero;
descRect.offsetMax = UnityEngine.Vector2.zero;
var descText = descObj.AddComponent<UnityEngine.UI.Text>();
descText.fontSize = 16;
descText.color = new UnityEngine.Color(0.7f, 0.7f, 0.7f, 1f);
descText.alignment = UnityEngine.TextAnchor.MiddleCenter;

// Price/Buy button area
var buyBtnObj = new UnityEngine.GameObject("BuyButton");
buyBtnObj.transform.SetParent(itemPrefabObj.transform, false);
var buyBtnRect = buyBtnObj.AddComponent<UnityEngine.RectTransform>();
buyBtnRect.anchorMin = new UnityEngine.Vector2(0.1f, 0.03f);
buyBtnRect.anchorMax = new UnityEngine.Vector2(0.9f, 0.13f);
buyBtnRect.offsetMin = UnityEngine.Vector2.zero;
buyBtnRect.offsetMax = UnityEngine.Vector2.zero;
var buyBtnImage = buyBtnObj.AddComponent<UnityEngine.UI.Image>();
buyBtnImage.color = new UnityEngine.Color(0.2f, 0.6f, 0.2f, 1f);
var buyBtn = buyBtnObj.AddComponent<UnityEngine.UI.Button>();

var priceTextObj = new UnityEngine.GameObject("PriceText");
priceTextObj.transform.SetParent(buyBtnObj.transform, false);
var priceTextRect = priceTextObj.AddComponent<UnityEngine.RectTransform>();
priceTextRect.anchorMin = UnityEngine.Vector2.zero;
priceTextRect.anchorMax = UnityEngine.Vector2.one;
priceTextRect.offsetMin = UnityEngine.Vector2.zero;
priceTextRect.offsetMax = UnityEngine.Vector2.zero;
var priceText = priceTextObj.AddComponent<UnityEngine.UI.Text>();
priceText.fontSize = 22;
priceText.fontStyle = UnityEngine.FontStyle.Bold;
priceText.color = UnityEngine.Color.white;
priceText.alignment = UnityEngine.TextAnchor.MiddleCenter;

// Tag label
var tagObj = new UnityEngine.GameObject("Tag");
tagObj.transform.SetParent(itemPrefabObj.transform, false);
var tagRect = tagObj.AddComponent<UnityEngine.RectTransform>();
tagRect.anchorMin = new UnityEngine.Vector2(0.65f, 0.78f);
tagRect.anchorMax = new UnityEngine.Vector2(0.98f, 0.92f);
tagRect.offsetMin = UnityEngine.Vector2.zero;
tagRect.offsetMax = UnityEngine.Vector2.zero;
var tagImage = tagObj.AddComponent<UnityEngine.UI.Image>();
tagImage.color = new UnityEngine.Color(1f, 0.3f, 0.3f, 1f);
var tagText = tagObj.AddComponent<UnityEngine.UI.Text>();
tagText.fontSize = 16;
tagText.fontStyle = UnityEngine.FontStyle.Bold;
tagText.color = UnityEngine.Color.white;
tagText.alignment = UnityEngine.TextAnchor.MiddleCenter;
tagObj.SetActive(false);

// Discount label
var discObj = new UnityEngine.GameObject("Discount");
discObj.transform.SetParent(itemPrefabObj.transform, false);
var discRect = discObj.AddComponent<UnityEngine.RectTransform>();
discRect.anchorMin = new UnityEngine.Vector2(0f, 0.78f);
discRect.anchorMax = new UnityEngine.Vector2(0.35f, 0.92f);
discRect.offsetMin = UnityEngine.Vector2.zero;
discRect.offsetMax = UnityEngine.Vector2.zero;
var discImage = discObj.AddComponent<UnityEngine.UI.Image>();
discImage.color = new UnityEngine.Color(1f, 0.6f, 0f, 1f);
var discText = discObj.AddComponent<UnityEngine.UI.Text>();
discText.fontSize = 16;
discText.fontStyle = UnityEngine.FontStyle.Bold;
discText.color = UnityEngine.Color.white;
discText.alignment = UnityEngine.TextAnchor.MiddleCenter;
discObj.SetActive(false);

// Sold out overlay
var soldOutObj = new UnityEngine.GameObject("SoldOut");
soldOutObj.transform.SetParent(itemPrefabObj.transform, false);
var soldOutRect = soldOutObj.AddComponent<UnityEngine.RectTransform>();
soldOutRect.anchorMin = UnityEngine.Vector2.zero;
soldOutRect.anchorMax = UnityEngine.Vector2.one;
soldOutRect.offsetMin = UnityEngine.Vector2.zero;
soldOutRect.offsetMax = UnityEngine.Vector2.zero;
var soldOutImage = soldOutObj.AddComponent<UnityEngine.UI.Image>();
soldOutImage.color = new UnityEngine.Color(0f, 0f, 0f, 0.6f);
var soldOutText = soldOutObj.AddComponent<UnityEngine.UI.Text>();
soldOutText.text = "已售罄";
soldOutText.fontSize = 32;
soldOutText.fontStyle = UnityEngine.FontStyle.Bold;
soldOutText.color = new UnityEngine.Color(1f, 0.5f, 0.5f, 1f);
soldOutText.alignment = UnityEngine.TextAnchor.MiddleCenter;
soldOutObj.SetActive(false);

// Add ShopItemUI component
var shopItemUI = itemPrefabObj.AddComponent<TowerDefense.UI.ShopItemUI>();

// Now wire up the ShopPanel references via SerializedField
// We need to use reflection since these are private
var spType = shopPanelComp.GetType();

// _shopPanel -> shopPanelObj
var shopPanelField = spType.GetField("_shopPanel", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
shopPanelField.SetValue(shopPanelComp, shopPanelObj);

// _closeButton
var closeButtonField = spType.GetField("_closeButton", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
closeButtonField.SetValue(shopPanelComp, closeBtn);

// _tabResource, _tabHero, _tabTower, _tabSpecial
var tabFields = new string[] {"_tabResource", "_tabHero", "_tabTower", "_tabSpecial"};
for (int i = 0; i < 4; i++)
{
    var field = spType.GetField(tabFields[i], System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
    field.SetValue(shopPanelComp, tabBtns[i]);
}

// _itemContainer
var itemContainerField = spType.GetField("_itemContainer", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
itemContainerField.SetValue(shopPanelComp, contentRect);

// _shopItemPrefab
var itemPrefabField = spType.GetField("_shopItemPrefab", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
itemPrefabField.SetValue(shopPanelComp, itemPrefabObj);

// Wire ShopItemUI references
var siuiType = shopItemUI.GetType();
siuiType.GetField("_iconImage", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, iconImage);
siuiType.GetField("_nameText", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, nameText);
siuiType.GetField("_descText", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, descText);
siuiType.GetField("_priceText", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, priceText);
siuiType.GetField("_tagText", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, tagText);
siuiType.GetField("_discountText", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, discText);
siuiType.GetField("_buyButton", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, buyBtn);
siuiType.GetField("_tagObject", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, tagObj);
siuiType.GetField("_discountObject", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, discObj);
siuiType.GetField("_soldOutObject", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, soldOutObj);

// Hide shop panel initially
shopPanelObj.SetActive(false);

// Save the item prefab as a prefab for reuse
UnityEditor.PrefabUtility.SaveAsPrefabAssetAndConnect(itemPrefabObj, "Assets/Prefabs/UI/ShopItemPrefab.prefab", UnityEditor.InteractionMode.UserAction);

UnityEngine.Debug.Log($"ShopPanel created successfully with all references wired!");
UnityEngine.Debug.Log($"  ShopPanel: {shopPanelObj.name}");
UnityEngine.Debug.Log($"  Tabs: {tabBtns.Length}");
UnityEngine.Debug.Log($"  ItemPrefab: {itemPrefabObj.name}");

