// Add ShopItemUI component
var shopItemUI = itemPrefabObj.AddComponent<TowerDefense.UI.ShopItemUI>();

// Now wire up the ShopPanel references via SerializedField
// We need to use reflection since these are private
var spType = shopPanelComp.GetType();

// _shopPanel -> shopPanelObj
var shopPanelField = spType.GetField("_shopPanel", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
shopPanelField.SetValue(shopPanelComp, shopPanelObj);

// _closeButton
var closeButtonField = spType.GetField("_closeButton", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
