siuiType.GetField("_nameText", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, nameText);
siuiType.GetField("_descText", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, descText);
siuiType.GetField("_priceText", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, priceText);
siuiType.GetField("_tagText", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, tagText);
siuiType.GetField("_discountText", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, discText);
siuiType.GetField("_buyButton", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, buyBtn);
siuiType.GetField("_tagObject", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, tagObj);
siuiType.GetField("_discountObject", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, discObj);
siuiType.GetField("_soldOutObject", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(shopItemUI, soldOutObj);

// Hide shop panel initially
shopPanelObj.SetActive(false);

// Save the item prefab as a prefab for reuse
UnityEditor.PrefabUtility.SaveAsPrefabAssetAndConnect(itemPrefabObj, "Assets/Prefabs/UI/ShopItemPrefab.prefab", UnityEditor.InteractionMode.UserAction);

UnityEngine.Debug.Log($"ShopPanel created successfully with all references wired!");
UnityEngine.Debug.Log($"  ShopPanel: {shopPanelObj.name}");
UnityEngine.Debug.Log($"  Tabs: {tabBtns.Length}");
UnityEngine.Debug.Log($"  ItemPrefab: {itemPrefabObj.name}");

