// Find the ShopPanel that was already created (it may have failed to set some fields)
var shopPanelComp = UnityEngine.Object.FindObjectOfType<TowerDefense.UI.ShopPanel>();
if (shopPanelComp != null)
{
    UnityEngine.Debug.Log($"Found ShopPanel on: {shopPanelComp.gameObject.name}");

    // Use SerializedObject to set references
    var so = new UnityEditor.SerializedObject(shopPanelComp);

    string[] fieldNames = {"_shopPanel", "_closeButton", "_tabResource", "_tabHero", "_tabTower", "_tabSpecial", "_itemContainer", "_shopItemPrefab"};
    foreach (var fn in fieldNames)
    {
        var prop = so.FindProperty(fn);
        if (prop != null)
        {
            UnityEngine.Debug.Log($"  {fn}: found (type={prop.type})");
        }
        else
        {
            UnityEngine.Debug.Log($"  {fn}: NOT FOUND");
        }
    }

    // Also check ShopItemUI
    var shopItemUI = shopPanelComp.GetComponentInChildren<TowerDefense.UI.ShopItemUI>();
    if (shopItemUI != null)
    {
        var so2 = new UnityEditor.SerializedObject(shopItemUI);
        string[] uiFields = {"_iconImage", "_nameText", "_descText", "_priceText", "_tagText", "_discountText", "_buyButton", "_tagObject", "_discountObject", "_soldOutObject"};
        foreach (var fn in uiFields)
        {
            var prop = so2.FindProperty(fn);
            UnityEngine.Debug.Log($"  ShopItemUI.{fn}: {(prop != null ? "found" : "NOT FOUND")}");
        }
    }
    else
    {
        UnityEngine.Debug.Log("ShopItemUI not found in children");
    }
}
else
{
    UnityEngine.Debug.Log("ShopPanel not found in scene");
}

