args.script:
// Wire the 商店 button to open ShopPanel
var shopPanelComp = UnityEngine.Object.FindObjectOfType<TowerDefense.UI.ShopPanel>();

// Find the 商店 button - it's under Canvas/ui按钮/商店
var canvas = UnityEngine.Object.FindObjectOfType<UnityEngine.Canvas>();
var uiButtons = canvas.transform.Find("ui按钮");
var shopButton = uiButtons?.Find("商店");

if (shopButton != null && shopPanelComp != null)
{
    var btn = shopButton.GetComponent<UnityEngine.UI.Button>();
    if (btn != null)
    {
        // Add persistent listener
        var targetInfo = UnityEditor.Events.UnityEventTools.AddPersistentListener(btn.onClick);
        targetInfo.SetTarget(shopPanelComp);
        targetInfo.SetMethodName("OpenShop");
        UnityEditor.EditorUtility.SetDirty(btn);
        UnityEngine.Debug.Log($"Wired 商店 button → ShopPanel.OpenShop()");
    }
    else
    {
        UnityEngine.Debug.Log("商店 has no Button component!");
    }
}
else
{
    UnityEngine.Debug.Log($"商店 button: {shopButton != null}, ShopPanel: {shopPanelComp != null}");
}

// Save the ShopItemPrefab
var content = canvas.transform.Find("ShopPanel/Frame/ScrollView/Viewport/Content");
var itemPrefab = content?.Find("ShopItemPrefab")?.gameObject;
if (itemPrefab != null)
{
    var prefabPath = "Assets/Prefabs/UI/ShopItemPrefab.prefab";
    UnityEditor.PrefabUtility.SaveAsPrefabAssetAndConnect(itemPrefab, prefabPath, UnityEditor.InteractionMode.UserAction);
    UnityEngine.Debug.Log($"Saved ShopItemPrefab to {prefabPath}");
}

UnityEngine.Debug.Log("Button wiring complete!");

